'use strict';
({params, imports}) => {
    const individual = params.entity;
    const moment = imports.moment;
    let eligibility = true;

    const childDevelopmentEnrolments = individual.enrolments.some(enrolment => enrolment.program.name == "Child Development Categorisation");
    if(!childDevelopmentEnrolments) return false;

    const age = individual.getAgeInYears(moment(), true);
    const ageISLessThan8Years = age <= 8;

    eligibility = ageISLessThan8Years;
    return eligibility;
};

'use strict';
({params, imports}) => {
  const individual = params.entity;
  function programNameEquals(enrolment, programName) {
    const program = enrolment.operationalProgramName || (enrolment.program && enrolment.program.name);
    return program === programName
  }

  function activeEnrolment(enl) {
    return programNameEquals(enl, 'Needs Assessment') &&
      enl.enrolmentDateTime &&
      enl.programExitDateTime === null &&
      !enl.voided;
  }

  let isThereAnyActiveEnrolment = individual.enrolments.some(activeEnrolment);

  return isThereAnyActiveEnrolment;
};

