        const enrolment = enrolments[0];

        const mannualCategorization = enrolment.getEncountersOfType('Manual categorization')
            .filter(enc => enc.encounterDateTime);

        if(mannualCategorization && mannualCategorization.length > 0){
            const latestEncounter = mannualCategorization[0];

            const selectedChildCategoryACT = latestEncounter.getObservationValue('3752c3dc-8067-48ea-b96d-55cc34320e94') || [];
            const selectedChildCategoryACT2 = latestEncounter.getObservationValue('9df88162-f16c-463c-b919-187c55512ba4') || [];

            const selectedOptions = [...(selectedChildCategoryACT || []), ...(selectedChildCategoryACT2 || [])];

            const isSelectedInOptions = selectedOptions.some(option => options.includes(option));

            eligibility = isSelectedInOptions;

            return eligibility;
        } 
    }

    return false;
};

