"use strict";
({ params, imports }) => {
  const programEncounter = params.entity;
  const moment = imports.moment;
  const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({programEncounter});

  const edd = programEncounter.programEnrolment.getObservationValue("Estimated Delivery Date");

  const deliveryEncounterCompleted = programEncounter.programEnrolment.getEncounters()
    .some(enc => enc.encounterType.name === 'Delivery' && enc.encounterDateTime);

  if (deliveryEncounterCompleted) {
    return scheduleBuilder.getAll(); // Stop scheduling if pregnancy is over
  };

  let numberOfAncEncounters = programEncounter.programEnrolment.getEncounters()
  .filter( enc => enc.encounterType.name === 'ANC' )
  .length;

  const earliestDate = moment(programEncounter.earliestVisitDateTime).add(30, 'days').toDate();
  const maxDate = moment(programEncounter.earliestVisitDateTime).add(37, 'days').toDate();
  let nextMonthDate = moment(programEncounter.cancelDateTime).add(1,'month').toDate();

  // Get all ANC encounters
  const previousANCs = programEncounter.programEnrolment.getEncounters()
    .filter(enc => enc.encounterType.name === "ANC")
    .sort((a, b) => moment(a.encounterDateTime || a.cancelDateTime).diff(moment(b.encounterDateTime || b.cancelDateTime))); // Sort by date

  const lastANC = previousANCs[previousANCs.length - 1]; // Get last PNC visit
  const lastANCNumber = lastANC.name[lastANC.name.length - 1];
  const currentANCNumber = programEncounter.name[programEncounter.name.length - 1];

  if ( edd && moment(earliestDate).isBefore(moment(edd)) && lastANCNumber <= currentANCNumber && !programEncounter.programEnrolment.programExitDateTime ) {
    scheduleBuilder.add({name: "ANC " + (numberOfAncEncounters + 1), encounterType: "ANC", earliestDate, maxDate});
    };

  return scheduleBuilder.getAll();
};

"use strict";

({ params, imports }) => {
  const programEncounter = params.entity;
  const moment = imports.moment;
  const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({ programEncounter });

  // Get all ANC encounters
  const previousANCs = programEncounter.programEnrolment.getEncounters()
    .filter(enc => enc.encounterType.name === "ANC")
    .sort((a, b) => moment(a.encounterDateTime || a.cancelDateTime).diff(moment(b.encounterDateTime || b.cancelDateTime))); // Sort by date

  // Get Estimated Delivery Date (EDD)
  const edd = programEncounter.programEnrolment.getObservationValue("Estimated Delivery Date");

  // Stop scheduling if delivery has happened
  const deliveryEncounterCompleted = programEncounter.programEnrolment.getEncounters()
    .some(enc => enc.encounterType.name === 'Delivery' && enc.encounterDateTime);

  if (deliveryEncounterCompleted) {
    return scheduleBuilder.getAll(); // Stop scheduling if pregnancy is over
  };

  // Schedule next ANC visit if previous ANC exists
  if (previousANCs.length > 0) {
    const lastANC = previousANCs[previousANCs.length - 1]; // Get last ANC visit
    const nextANCNumber = previousANCs.length + 1; // Determine ANC visit number
    let nextMonthDate = moment(programEncounter.encounterDateTime).add(1,'month').toDate();

    const dueDate = moment(programEncounter.encounterDateTime || programEncounter.earliestVisitDateTime).add(30, "days").toDate();
    const maxDate = moment(programEncounter.encounterDateTime || programEncounter.earliestVisitDateTime).add(37, "days").toDate();

    const checkIfVisitScheduledInNextMonth = () => {
    return programEncounter.programEnrolment.getEncounters()
    .filter(enc => enc.encounterType.name === 'ANC' && moment(enc.earliestVisitDateTime).format('MM-YYYY') == moment(nextMonthDate).format('MM-YYYY'))
    };

    if ( edd && moment(dueDate).isBefore(moment(edd)) && !programEncounter.programEnrolment.programExitDateTime && checkIfVisitScheduledInNextMonth().length == 0 ) {
        scheduleBuilder.add({
          name: "ANC " + nextANCNumber,
          encounterType: "ANC",
          earliestDate: dueDate,
          maxDate
        });
    }
  }

  return scheduleBuilder.getAll();
};

