"use strict";
({ params, imports }) => {
    const programEncounter = params.entity;
    const moment = imports.moment;
    const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({programEncounter});

    const individual = programEncounter.programEnrolment.individual;
    const earliestVisitDateTime = programEncounter.earliestVisitDateTime;

    const isActive = !programEncounter.programEnrolment.programExitDateTime;

    if (!isActive) {
        return scheduleBuilder.getAll();
    }

    const nextVisitDate = moment(earliestVisitDateTime).add(3, 'months').startOf('day');

    const assessment42Encounters = programEncounter.programEnrolment.getEncountersOfType('Assessment 42') || [];
    const alreadyScheduled = assessment42Encounters.some((enc) => moment(enc.earliestVisitDateTime).startOf('day').isSame(nextVisitDate, 'day'));

    if(!alreadyScheduled){
        const earliestDate = nextVisitDate.toDate();
        const maxDate = moment(earliestDate).add(1, 'month').toDate();
        scheduleBuilder.add({
            name: "Assessment 42", 
            encounterType: "Assessment 42", 
            earliestDate, 
            maxDate
        });  
    }

    return scheduleBuilder.getAll();
};

"use strict";
({ params, imports }) => {
    const programEncounter = params.entity;
    const individual = programEncounter.programEnrolment.individual;
    const moment = imports.moment;
    const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({programEncounter});

    const encounterDateTime = programEncounter.encounterDateTime;

    const isActive = !programEncounter.programEnrolment.programExitDateTime;

    if (!isActive) {
        return scheduleBuilder.getAll();
    }

    const nextVisitDate = moment(encounterDateTime).add(3, 'months').startOf('day');

    const assessment42Encounters = programEncounter.programEnrolment.getEncountersOfType('Assessment 42') || [];
    const alreadyScheduled = assessment42Encounters.some((enc) => moment(enc.earliestVisitDateTime).startOf('day').isSame(nextVisitDate, 'day'));
    const ageInMonths = individual.getAgeInMonths(nextVisitDate, false);

    if(!alreadyScheduled && ageInMonths <= 36){
        const earliestDate = nextVisitDate.toDate();
        const maxDate = moment(earliestDate).add(1, 'month').endOf('day').toDate();
        scheduleBuilder.add({
            name: "Assessment 42", 
            encounterType: "Assessment 42", 
            earliestDate, 
            maxDate
        });  
    }

    const nextVisitDate2 = moment(encounterDateTime);

    const manualCategorizationEncounters = programEncounter.programEnrolment.getEncountersOfType('Manual categorization') || [];
    const alreadyScheduled2 = manualCategorizationEncounters.some(
        enc=> enc.earliestVisitDateTime != null && moment(enc.earliestVisitDateTime).isSame(nextVisitDate2, 'day')
    );

    if(!alreadyScheduled2){
        const earliestDate = nextVisitDate2.toDate();
