  } else if (["SAM", "MAM", "SUW", "MUW"].includes(growthStatus)) {
    daysBeforeSchedule = 3;
  } else {
    daysBeforeSchedule = 0; // Default if status is missing
  }

  const earliestVisitDateTime = moment(programEncounter.earliestVisitDateTime).subtract(daysBeforeSchedule, 'days').format('YYYY-MM-DD');

  // Validation checks
  if (!(encounterDateTime >= earliestVisitDateTime)) {
    validationErrors.push("This visit cannot be completed sooner");
  }

  if (encounterDateTime >= maxVisitDateTime) {
    validationErrors.push("Overdue forms cannot be filled, please cancel this form so that the next due form can be scheduled");
  }

  return new imports.rulesConfig.FormElementStatus(formElement.uuid, true, null, [], validationErrors);
};

