    visibility = doYouWantToContinue ;

    const currentCancelDateTime = moment(programEncounter.cancelDateTime).startOf('day');

    let selectedDate = programEncounter.findCancelEncounterObservation('4c94aa47-5e4d-4cc3-a0b6-b8378a516b11');

    if(selectedDate) {
        selectedDate = moment(selectedDate.getValue()).startOf('day');
        const twoWeeksLater = currentCancelDateTime.clone().add(2, 'weeks').startOf('day');
        if (selectedDate.isAfter(twoWeeksLater, 'day')) {
            validationErrors.push('Date should not be beyond 2 weeks of current encounter');
        }
        if (selectedDate.isSameOrBefore(currentCancelDateTime, 'day')) {
            validationErrors.push('Date should be After current visit date');
        }
    }

    return new imports.rulesConfig.FormElementStatus(formElement.uuid, visibility, value, answersToSkip, validationErrors);
};

