    const formElement = params.formElement;
    const _ = imports.lodash;
    let visibility = true;
    let value = null;
    let answersToSkip = [];
    let validationErrors = [];

    const doYouWantToContinue = new imports.rulesConfig.RuleCondition({programEncounter, formElement}).when.valueInEncounter("9efc5f8d-07f3-483c-a6b0-4137dc6ebce6").containsAnswerConceptName("d7e55b4b-2674-44b3-a777-47fe323c783a").matches();

    visibility = doYouWantToContinue;

    const currentEncounterDateTime = moment(programEncounter.encounterDateTime).startOf('day');

    let selectedDate = programEncounter.getObservationValue('4c94aa47-5e4d-4cc3-a0b6-b8378a516b11');

    if(selectedDate) {
        selectedDate = moment(selectedDate).startOf('day');
        const twoWeeksLater = currentEncounterDateTime.clone().add(2, 'weeks');
        if (selectedDate.isAfter(twoWeeksLater, 'day')) {
            validationErrors.push('Date should not be beyond 2 weeks of current encounter');
        }
        if (selectedDate.isSameOrBefore(currentEncounterDateTime, 'day')) {
            validationErrors.push('Date should be After current visit date');
        }
    }

    return new imports.rulesConfig.FormElementStatus(formElement.uuid, visibility, value, answersToSkip, validationErrors);
};

