"use strict";
({ params, imports }) => {
    const programEncounter = params.entity;
    const moment = imports.moment;
    const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({programEncounter});

    const individual = programEncounter.programEnrolment.individual;
    const encounterDateTime = programEncounter.encounterDateTime;

    const isActive = !programEncounter.programEnrolment.programExitDateTime;

    if (!isActive) {
        return scheduleBuilder.getAll();
    }

    const nextVisitDate = moment(encounterDateTime).add(2, 'weeks').startOf('day');

    const ageInMonths = individual.getAgeInMonths(nextVisitDate, false);

    if(ageInMonths <= 36) {

        const alreadyScheduled = programEncounter.programEnrolment.getEncountersOfType('Assessment 42') || [];

        if(alreadyScheduled == undefined || alreadyScheduled.length == 0){
            const earliestDate = nextVisitDate.toDate();
            const maxDate = moment(earliestDate).add(1, 'month').endOf('day').toDate();
            scheduleBuilder.add({
                name: "Assessment 42",
                encounterType: "Assessment 42", 
                earliestDate, 
                maxDate
            });  
        }
    }

    if (ageInMonths >= 37 && ageInMonths <= 72) {

        const alreadyScheduled = programEncounter.programEnrolment.getEncountersOfType("Milestone assessment") || [];

        if(alreadyScheduled == undefined || alreadyScheduled.length == 0) {
            const earliestDate = nextVisitDate.toDate();
            const maxDate = moment(earliestDate).add(45, 'days').endOf('day').toDate();
            scheduleBuilder.add({
                name: "Milestone assessment", 
                encounterType: "Milestone assessment", 
                earliestDate, 
                maxDate
            }); 
        }
    }

    return scheduleBuilder.getAll();
};

