"use strict";
({ params, imports }) => {
  const programEnrolment = params.entity;
  const moment = imports.moment;
  const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({ programEnrolment });

  const allEncounters = programEnrolment.getEncounters() || [];

  const completedVisits = allEncounters.filter(enc =>
    enc &&
    enc.encounterType &&
    enc.encounterType.name === "Mantrana individual activity tracking"
  );

  // Stop scheduling beyond 6
  if (completedVisits.length >= 6) {
    return scheduleBuilder.getAll();
  }

  const earliestDate = moment(programEnrolment.enrolmentDateTime).add(7, "days").toDate();
  const maxDate = moment(programEnrolment.enrolmentDateTime).add(9, "days").toDate();

  const isDuplicate = allEncounters.some(enc =>
    enc &&
    enc.encounterType &&
    enc.encounterType.name === "Mantrana individual activity tracking" &&
    enc.earliestVisitDateTime &&
    moment(enc.earliestVisitDateTime).isBetween(
      moment(earliestDate).startOf("day"),
      moment(maxDate).endOf("day"),
      undefined,
      "[]"
    )
  );

  if (!isDuplicate) {
    scheduleBuilder.add({
      name: "Mantrana individual activity tracking",
      encounterType: "Mantrana individual activity tracking",
      earliestDate,
      maxDate
    });
  }

  return scheduleBuilder.getAll();
};

