"use strict";
({ params, imports })=> {
  const programEncounter = params.entity;
  const moment = imports.moment;
  const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({ programEncounter });

  const dateOfNextFollowupDefined = new imports.rulesConfig.RuleCondition({programEncounter}).when.valueInEncounter("5bbc2c01-b8aa-4fae-b151-8e187c5f2c23").defined.matches();

  let numberOfReferralFollowUpEncounters = programEncounter.programEnrolment.getEncounters()
    .filter(enc => enc.encounterType.name === "Mantrana - Referral Follow up")
    .length;

  const previousMantranaReferralVisits = programEncounter.programEnrolment.getEncounters()
  .filter(enc => enc.encounterType.name === "Mantrana - Referral Follow up")
  .sort((a, b) => moment(a.encounterDateTime || a.cancelDateTime).diff(moment(b.encounterDateTime || b.cancelDateTime))); // Sort by date

  const lastMantranaReferralVisit = previousMantranaReferralVisits[previousMantranaReferralVisits.length - 1]; // Get last referreal visit
  const lastMantranaReferralVisitNumber = lastMantranaReferralVisit.name[lastMantranaReferralVisit.name.length - 1];
  const currentEncNumber = programEncounter.name[programEncounter.name.length - 1];

  if (dateOfNextFollowupDefined && lastMantranaReferralVisitNumber <= currentEncNumber) {

    const nextFollowUpDate = moment(programEncounter.getObservationValue("5bbc2c01-b8aa-4fae-b151-8e187c5f2c23")).toDate();
    const earliestDate = nextFollowUpDate ;
    const maxDate = moment(nextFollowUpDate).add(3,'days').toDate();

    if (!programEncounter.programEnrolment.programExitDateTime) {
      scheduleBuilder.add({
        name: "Mantrana - Referral Follow up " + (numberOfReferralFollowUpEncounters + 1),
        encounterType: "Mantrana - Referral Follow up",
        earliestDate,
        maxDate
      });
    }
  }

  return scheduleBuilder.getAll();
}

