"use strict";
({ params, imports }) => {
  const programEncounter = params.entity;
  const moment = imports.moment;
  const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({ programEncounter });

  const allEncounters = programEncounter.programEnrolment.getEncounters() || [];

  // Count COMPLETED visits
  const completedVisits = allEncounters.filter(enc =>
    enc &&
    enc.encounterType &&
    enc.encounterType.name == "Mantrana individual activity tracking"
  );

  // Schedule only if less than 6 completed visits
  if (completedVisits.length < 6) {
    // Calculate planned visit dates
    const earliestDate = moment(programEncounter.encounterDateTime).add(7, 'days').toDate();
    const maxDate = moment(programEncounter.encounterDateTime).add(9, 'days').toDate();

    // Prevent duplicate scheduling for the same planned week
    const duplicateCheck = allEncounters.some(enc =>
      enc &&
      enc.encounterType &&
      enc.encounterType.name === "Mantrana individual activity tracking" &&
      enc.earliestVisitDateTime &&
      moment(enc.earliestVisitDateTime).isSame(moment(earliestDate), "week")
    );

    if (!duplicateCheck) {
      scheduleBuilder.add({
        name: "Mantrana individual activity tracking",
        encounterType: "Mantrana individual activity tracking",
        earliestDate,
        maxDate
      });
    }
  }

  return scheduleBuilder.getAll();
};

