"use strict";
({ params, imports }) => {
    const programEnrolment = params.entity;
    const moment = imports.moment;
    const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({programEnrolment});
    const enrolmentDateTime = programEnrolment.enrolmentDateTime

    const isActive = !programEnrolment.programExitDateTime;

    if (!isActive) {
        return scheduleBuilder.getAll();
    }

    const alreadyScheduled = programEnrolment.getEncountersOfType("NK Individual referral follow up") || [];

    if(alreadyScheduled == undefined || alreadyScheduled.length == 0){
        const earliestDate = moment(enrolmentDateTime).add(15, 'days').startOf('day').toDate();
        const maxDate = moment(earliestDate).add(3, 'days').endOf('day').toDate();
        scheduleBuilder.add({
            name: "NK Individual referral follow up", 
            encounterType: "NK Individual referral follow up", 
            earliestDate, 
            maxDate
        });  
    }

    return scheduleBuilder.getAll();
};

