"use strict";
({ params, imports }) => {
  const programEncounter = params.entity;
  const moment = imports.moment;
  const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({ programEncounter });

  // Check if the "Date of next follow up visit" is defined in the encounter
  const dateOfNextFollowupDefined = new imports.rulesConfig.RuleCondition({ programEncounter })
    .when.valueInEncounter("9332f042-3fc0-4498-ac94-6ca12757a0d7")  // UUID of "Date of next follow up visit"
    .defined
    .matches();

  let numberOfReferralFollowUpEncounters = programEncounter.programEnrolment.getEncounters()
    .filter(enc => enc.encounterType.name === "Need Assessment - Referral Follow up") // The "Need Assessment - Referral Follow up" encounter
    .length;

  // Proceed if the "Date of next follow up visit" is defined
  if (dateOfNextFollowupDefined) {
    // Get the "Date of next follow up visit" and convert it to a Date object
    const nextFollowUpDate = moment(programEncounter.getObservationValue("9332f042-3fc0-4498-ac94-6ca12757a0d7")).toDate();

    // Define the earliest date and max date for the next visit
    const earliestDate = nextFollowUpDate;
    const maxDate = moment(nextFollowUpDate).add(7, 'days').toDate();  // Schedule within 7 days of the next follow-up date

const previousNeedsAssessments = programEncounter.programEnrolment.getEncounters()
    .filter(enc => enc.encounterType.name === "Need Assessment - Referral Follow up")
    .sort((a, b) => moment(a.encounterDateTime || a.cancelDateTime).diff(moment(b.encounterDateTime || b.cancelDateTime))); // Sort by date

  const lastNeedsAssessment = previousNeedsAssessments[previousNeedsAssessments.length - 1];
  const lastNeedsAssessmentNumber = lastNeedsAssessment.name[lastNeedsAssessment.name.length - 1];
  const currentNeedsAssessmentNumber = programEncounter.name[programEncounter.name.length - 1];

  if (lastNeedsAssessmentNumber <= currentNeedsAssessmentNumber && !programEncounter.programEnrolment.programExitDateTime) {
      scheduleBuilder.add({
        name: "Need Assessment - Referral Follow up " + (numberOfReferralFollowUpEncounters + 1),
        encounterType: "Need Assessment - Referral Follow up", // Correct encounter type
        earliestDate,
        maxDate
      });
    }
}

  return scheduleBuilder.getAll();
};

