  const cannotGetPregnant = new imports.rulesConfig.RuleCondition({ programEncounter })
    .when.valueInEncounter("If No, why?")
    .containsAnyAnswerConceptName("Infertility", "Menopause", "Hysterectomy")
    .matches();

  if (cannotGetPregnant) {
    return scheduleBuilder.getAll();
  }

  // Condition: If the woman is trying to get pregnant - Schedule in 30 days
  const tryingToGetPregnant = new imports.rulesConfig.RuleCondition({ programEncounter })
    .when.valueInEncounter("If No, why?")
    .containsAnyAnswerConceptName("Trying to get pregnant")
    .matches();

  if (tryingToGetPregnant) {
    const earliestDate = moment(programEncounter.encounterDateTime).add(30, "days").toDate();
    const maxDate = moment(programEncounter.encounterDateTime).add(37, "days").toDate();

    // Correcting the counting logic here
    let numberOfNeedsAssessmentEncounters = programEncounter.programEnrolment.getEncounters()
      .filter(enc => enc.encounterType.name === 'Needs Assessment Home Visit')
      .length;

    if(!programEncounter.programEnrolment.programExitDateTime){
      scheduleBuilder.add({
        name: "Needs Assessment Home Visit " + (numberOfNeedsAssessmentEncounters + 1),
        encounterType: "Needs Assessment Home Visit",
        earliestDate,
        maxDate
      });
    }
    return scheduleBuilder.getAll();
  }

  // If the woman is NOT trying but CAN get pregnant - Schedule in 60 days
  const earliestDate = moment(programEncounter.encounterDateTime).add(60, "days").toDate();
  const maxDate = moment(programEncounter.encounterDateTime).add(67, "days").toDate();

  // Counting the number of "Needs Assessment Home Visit" encounters correctly
  let numberOfNeedsAssessmentEncounters = programEncounter.programEnrolment.getEncounters()
    .filter(enc => enc.encounterType.name === 'Needs Assessment Home Visit')
    .length;

  const previousNeedsAssessments = programEncounter.programEnrolment.getEncounters()
    .filter(enc => enc.encounterType.name === "Needs Assessment Home Visit")
    .sort((a, b) => moment(a.encounterDateTime || a.cancelDateTime).diff(moment(b.encounterDateTime || b.cancelDateTime))); // Sort by date

  const lastNeedsAssessment = previousNeedsAssessments[previousNeedsAssessments.length - 1]; // Get last PNC visit
  const lastNeedsAssessmentNumber = lastNeedsAssessment.name[lastNeedsAssessment.name.length - 1];
  const currentNeedsAssessmentNumber = programEncounter.name[programEncounter.name.length - 1];

  if (lastNeedsAssessmentNumber <= currentNeedsAssessmentNumber && !programEncounter.programEnrolment.programExitDateTime) {
      scheduleBuilder.add({
        name: "Needs Assessment Home Visit " + (numberOfNeedsAssessmentEncounters + 1),
        encounterType: "Needs Assessment Home Visit",
        earliestDate,
        maxDate
      });
  }

  return scheduleBuilder.getAll();
};

