({ params, imports }) => {
  const programEncounter = params.entity;
  const moment = imports.moment;
  const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({ programEncounter });

  // Fetch latest Delivery visit
  const deliveryEncounter = programEncounter.programEnrolment.getEncountersOfType("Delivery").sort(
    (a, b) => moment(b.encounterDateTime).diff(moment(a.encounterDateTime))
  )[0];

  // Fetch "Date of delivery" from the latest Delivery encounter
  const dateOfDelivery = deliveryEncounter.getObservationValue("Date of delivery");

  if (!dateOfDelivery) {
    return scheduleBuilder.getAll();
  }

  // Calculate days since delivery
  const daysSinceDelivery = moment(programEncounter.cancelDateTime).diff(moment(dateOfDelivery), "days");

  let earliestDate, maxDate;

  if (daysSinceDelivery >= 0 && daysSinceDelivery <= 23) {
    earliestDate = moment(programEncounter.cancelDateTime).add(7, "days").toDate();
    maxDate = moment(earliestDate).add(2, "days").toDate();
  } else if (daysSinceDelivery >= 24 && daysSinceDelivery <= 46) {
    earliestDate = moment(programEncounter.cancelDateTime).add(14, "days").toDate();
    maxDate = moment(earliestDate).add(3, "days").toDate();
  } else if (daysSinceDelivery >= 47 && daysSinceDelivery <= 150) {
    earliestDate = moment(programEncounter.cancelDateTime).add(30, "days").toDate();
    maxDate = moment(earliestDate).add(7, "days").toDate();
  } else {
    return scheduleBuilder.getAll();
  }

  // **Add Numbering for PNC Visits**
  let numberOfPNCVisits = programEncounter.programEnrolment.getEncounters()
    .filter(enc => enc.encounterType.name === 'PNC')
    .length;

  // Get all PNC encounters
  const previousPNCs = programEncounter.programEnrolment.getEncounters()
    .filter(enc => enc.encounterType.name === "PNC")
    .sort((a, b) => moment(a.encounterDateTime || a.cancelDateTime).diff(moment(b.encounterDateTime || b.cancelDateTime))); // Sort by date

  const lastPNC = previousPNCs[previousPNCs.length - 1]; // Get last PNC visit
  const lastPNCNumber = lastPNC.name[lastPNC.name.length - 1];
  const currentPNCNumber = programEncounter.name[programEncounter.name.length - 1];


  // Add visit schedule with numbering
  if (lastPNCNumber <= currentPNCNumber && !programEncounter.programEnrolment.programExitDateTime ) {
      scheduleBuilder.add({
        name: "PNC Visit " + (numberOfPNCVisits + 1), // Added numbering here
        encounterType: "PNC",
        earliestDate,
        maxDate
      });
}
  return scheduleBuilder.getAll();
};

