  let numberOfReferralFollowUpEncounters = programEncounter.programEnrolment.getEncounters()
    .filter(enc => enc.encounterType.name === "Pregnancy - Referral Follow up")
    .length;

  const previousPregnancyReferrals = programEncounter.programEnrolment.getEncounters()
    .filter(enc => enc.encounterType.name === "Pregnancy - Referral Follow up")
    .sort((a, b) => moment(a.encounterDateTime || a.cancelDateTime).diff(moment(b.encounterDateTime || b.cancelDateTime))); // Sort by date

  const lastPregnancyReferral = previousPregnancyReferrals[previousPregnancyReferrals.length - 1]; 
  const lastPregnancyReferralNumber = lastPregnancyReferral.name[lastPregnancyReferral.name.length - 1];
  const currentPregnancyReferralNumber = programEncounter.name[programEncounter.name.length - 1];

  if (dateOfNextFollowupDefined && lastPregnancyReferralNumber <= currentPregnancyReferralNumber) {

    const nextFollowUpDate = moment(programEncounter.getObservationValue("9332f042-3fc0-4498-ac94-6ca12757a0d7")).toDate();
    const earliestDate = nextFollowUpDate ;
    const maxDate = moment(nextFollowUpDate).add(7,'days').toDate();

    if (!programEncounter.programEnrolment.programExitDateTime) {
      scheduleBuilder.add({
        name: "Pregnancy - Referral Follow up " + (numberOfReferralFollowUpEncounters + 1),
        encounterType: "Pregnancy - Referral Follow up",
        earliestDate,
        maxDate
      });
    }
  }

  return scheduleBuilder.getAll();
}

