"use strict";
({ params, imports }) => {
    const programEncounter = params.entity;
    const individual = programEncounter.programEnrolment.individual;
    const moment = imports.moment;
    const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({ programEncounter });
    const cancelDateTime = programEncounter.cancelDateTime;
    const cancelDateTimeMoment = moment(programEncounter.cancelDateTime);

    // Check if the encounter is already scheduled
    function alreadyScheduled(encounterType, nextFollowupName, earliestDate){
        const momentEarliestDate = moment(earliestDate).startOf('day');
        const encounters = programEncounter.programEnrolment.getEncountersOfType(encounterType);
        return encounters && encounters.length > 0 && encounters.some(
            encounter => {
                const momentEarliestVisitDate = moment(encounter.earliestVisitDateTime).startOf('day');
                return momentEarliestVisitDate.isSame(momentEarliestDate) && encounter.name == nextFollowupName;
            }
        );
    }

    // Get next follow up name
    function getNextFollowUpName(currentFollowupName) {
        // If empty or not provided → return the first follow-up
        if (!currentFollowupName || currentFollowupName.trim() === "") {
            return "Child Home Visit Anthropometry 1";
        }

        // Normalize multiple spaces → single space
        const name = currentFollowupName.trim().replace(/\s+/g, ' ');
        const parts = name.split(' ');

        // Last word should be the number
        const lastPart = parts[parts.length - 1];
        const currentNumber = parseInt(lastPart, 10);

        // If last part is NOT a number → treat as first follow-up
        if (isNaN(currentNumber)) {
            return "Child Home Visit Anthropometry 1";
        }

        // Otherwise increment normally
        const nextNumber = currentNumber + 1;
        return `Child Home Visit Anthropometry ${nextNumber}`;
    }

    // Next Followup Name;
    const currentFollowupName = programEncounter.name;
    const nextFollowupName = getNextFollowUpName(currentFollowupName);

    // Counting previous "Child Home Visit Anthropometry" encounters
    let childHomeVisitEncounters = programEncounter.programEnrolment.getEncountersOfType('Child Home Visit Anthropometry') || [];
    const allCompletedChildHomeVisit = childHomeVisitEncounters.filter(enc => enc.encounterDateTime)

    // By default schedule in 30 days
    let earliestDate = moment(cancelDateTime).add(30, "days").startOf("day").toDate();
    let maxDate = moment(cancelDateTime).add(37, "days").endOf("day").toDate();

    if (allCompletedChildHomeVisit.length > 0) {
        const latestCompletedChildHomeVisitObservation = allCompletedChildHomeVisit[0];

        // Fetch necessary observation values
        const weightForHeightZScore = latestCompletedChildHomeVisitObservation.getObservationValue("Weight for height z-score");
        const weightForAgeZScore = latestCompletedChildHomeVisitObservation.getObservationValue("Weight for age z-score");

        // Calculate the child's age in years
        const ageInYears = individual.getAgeInYears(cancelDateTimeMoment);

        // Condition: If child is SAM (Severe Acute Malnutrition) - Schedule in 15 days
        const isSAM = weightForHeightZScore <= -3 || weightForAgeZScore <= -3;

        // Condition: If child is MAM (Moderate Acute Malnutrition) - Schedule in 15 days
        const isMAM = (weightForHeightZScore > -3 && weightForHeightZScore <= -2) || (weightForAgeZScore > -3 && weightForAgeZScore <= -2);

        // Condition: If child is "Normal" and less than 2 years old - Schedule in 30 days
        const isNormalUnder2 = ageInYears < 2 && !isSAM && !isMAM;

        if(isSAM || isMAM){
            earliestDate = moment(cancelDateTime).add(15, "days").startOf("day").toDate();
            maxDate = moment(cancelDateTime).add(20, "days").endOf("day").toDate();

            if(!alreadyScheduled('Child Home Visit Anthropometry', nextFollowupName, earliestDate)){
                scheduleBuilder.add({
                    name: nextFollowupName,
                    encounterType: "Child Home Visit Anthropometry",
                    earliestDate: earliestDate,
                    maxDate: maxDate,
                });
            }
        }else if(isNormalUnder2){
            earliestDate = moment(cancelDateTime).add(30, "days").startOf("day").toDate();
            maxDate = moment(cancelDateTime).add(37, "days").endOf("day").toDate();

            if(!alreadyScheduled('Child Home Visit Anthropometry', nextFollowupName, earliestDate)){
                scheduleBuilder.add({
                    name: nextFollowupName,
                    encounterType: "Child Home Visit Anthropometry",
                    earliestDate: earliestDate,
                    maxDate: maxDate,
                });
            }
        }
    }
    else if(!alreadyScheduled('Child Home Visit Anthropometry', nextFollowupName, earliestDate)){

        scheduleBuilder.add({
            name: nextFollowupName,
            encounterType: "Child Home Visit Anthropometry",
            earliestDate: earliestDate,
            maxDate: maxDate,
        });
    }

    return scheduleBuilder.getAll();
};

