  const dateOfDelivery = deliveryEncounter.getObservationValue("Date of delivery");

  if (!dateOfDelivery) {
    return scheduleBuilder.getAll();
  }

  // Calculate days since delivery
  const daysSinceDelivery = moment(programEncounter.cancelDateTime).diff(moment(dateOfDelivery), "days");

  let earliestDate, maxDate;

  if (daysSinceDelivery >= 0 && daysSinceDelivery <= 23) {
    earliestDate = moment(programEncounter.cancelDateTime).add(7, "days").toDate();
    maxDate = moment(earliestDate).add(2, "days").toDate();
  } else if (daysSinceDelivery >= 24 && daysSinceDelivery <= 46) {
    earliestDate = moment(programEncounter.cancelDateTime).add(14, "days").toDate();
    maxDate = moment(earliestDate).add(3, "days").toDate();
  } else if (daysSinceDelivery >= 47 && daysSinceDelivery <= 150) {
    earliestDate = moment(programEncounter.cancelDateTime).add(30, "days").toDate();
    maxDate = moment(earliestDate).add(7, "days").toDate();
  } else {
    return scheduleBuilder.getAll();
  }

  // **Add Numbering for PNC Visits**
  let numberOfPNCVisits = programEncounter.programEnrolment.getEncounters()
    .filter(enc => enc.encounterType.name === 'PNC')
    .length;

  // Get all PNC encounters
