    const programEnrolment = programEncounter.programEnrolment;

    const currentEncounterQuestionGroup = programEncounter.getObservationValue('7d06a63c-4f78-4519-acec-9b8bc1a85fce') || [];

    if(currentEncounterQuestionGroup && currentEncounterQuestionGroup.length > questionGroupIndex) {
        const currentGroup = currentEncounterQuestionGroup[questionGroupIndex];
        currentTypeOfGoal = currentGroup.findObservationByConceptUUID('7060522e-e88b-470a-aaa6-ceba986e4169');
        currentDescription = currentGroup.findObservationByConceptUUID('29700074-36f5-4245-8aba-3c57ffa839f8');
        currentStatus = currentGroup.findObservationByConceptUUID('cd5304c5-870f-420b-8929-1fc8b3dd9be3');
        if(currentTypeOfGoal && currentStatus && currentDescription) {
            currentTypeOfGoal = currentTypeOfGoal.getValue();
            currentDescription = currentDescription.getValue();
            currentStatus = currentStatus.getValue();
        }
    }

    let allOptions = {
        '333874ea-c391-41c2-aff1-b249c44cf235': {name: 'New Goal', level: 1},
        '9f22d112-45dc-4045-a8d0-c54c8e4304d4': {name: 'Ongoing', level: 2},
        '2a43890e-a1e8-4289-bb5e-80a239a14d1e': {name: 'Achieved', level: 3}
    }

    function levelSIsSameOrGreater(level1, level2) {

        const level1Value = allOptions[level1];
        const level2Value = allOptions[level2];
        if(level1Value && level2Value) {
            if(level2Value.level >= level1Value.level) {
                return {
                    value: true,
                    message: 'Level is same or greater'
                };
            }
            else if(level1Value.name == 'Ongoing'){
                return {
                    value: false,
                    message: 'This goal is already ongoing; are you sure you want to edit it?'
                };
            }
            else if(level1Value.name == 'Achieved') {
                return {
                    value: false,
                    message: 'This goal is already achieved; are you sure you want to edit it?'
                };
            }
        }

        return {
            value: true,
            message: 'Don\'t know'
        };
    }

    const encounters = programEnrolment.getEncountersOfType(encounterType) || [];
    const previousEncounters = encounters.filter(enc => enc.uuid != programEncounter.uuid);

    if(previousEncounters.length > 0 && currentEncounterQuestionGroup.length > 0 && currentTypeOfGoal && currentStatus && currentDescription) {
        const latestPreviousEncoutner = previousEncounters[0];
        const questionGroup = latestPreviousEncoutner.getObservationValue('7d06a63c-4f78-4519-acec-9b8bc1a85fce') || [];

        for (let i = 0; i < questionGroup.length; i++) {
            const currentGroup = questionGroup[i];
            let previousTypeOfgoal = currentGroup.findObservationByConceptUUID('7060522e-e88b-470a-aaa6-ceba986e4169');
            let previousStatus = currentGroup.findObservationByConceptUUID('cd5304c5-870f-420b-8929-1fc8b3dd9be3');
            let previousDescription = currentGroup.findObservationByConceptUUID('29700074-36f5-4245-8aba-3c57ffa839f8');
            if (previousTypeOfgoal && previousStatus && previousDescription) {
                previousTypeOfgoal = previousTypeOfgoal.getValue();
                previousStatus = previousStatus.getValue();
                previousDescription = previousDescription.getValue();
                if(previousTypeOfgoal == currentTypeOfGoal && previousDescription == currentDescription) {
                    const result = levelSIsSameOrGreater(previousStatus, currentStatus);
                    if(!result.value) {
                        validationErrors.push(result.message);
                    }
                }
            }
        }
    }

    return new imports.rulesConfig.FormElementStatus(formElement.uuid, visibility, value, answersToSkip, validationErrors);
};

