'use strict';
({params, imports}) => {
    const programEncounter = params.entity;
    const moment = imports.moment;
    const formElement = params.formElement;
    const _ = imports.lodash;
    let visibility = true;
    let value = null;
    let answersToSkip = [];
    let validationErrors = [];
    const encounterType = programEncounter.encounterType.name;

    let nextFollowupDate = programEncounter.getObservationValue('Select date of next visit');

    const ptot_therapy_visit = programEncounter.programEnrolment.getEncountersOfType(encounterType);

    if (ptot_therapy_visit && ptot_therapy_visit.length > 0 && nextFollowupDate) {
        nextFollowupDate = moment(nextFollowupDate).startOf('day');
        const visitIsAlreadyScheduledOnTheSameDateOrAfter = ptot_therapy_visit.some(visit => {
            const visitDate = moment(visit.earliestVisitDateTime).startOf('day');
            return visitDate.isSameOrAfter(nextFollowupDate, 'day');
        });
        if (visitIsAlreadyScheduledOnTheSameDateOrAfter) {
            validationErrors.push(`A follow-up visit is already scheduled for this date or later. Please select a different date.`);
        }
    }

    return new imports.rulesConfig.FormElementStatus(formElement.uuid, visibility, value, answersToSkip, validationErrors);
};

