  const mcpDate = programEnrolment.getObservationValue('Pregnancy registration date as per Mamta card');

  // ✅ Only continue if both values exist
  if (lmp && mcpDate) {

    // ✅ Define moments correctly
    const lmpMoment = moment(lmp);
    const mcpMoment = moment(mcpDate);

    // 1️⃣ MCP must be after LMP
    if (mcpMoment.isBefore(lmpMoment, 'day')) {
      validationErrors.push("either the MCP card registration or the LMP date is incorrect. Please contact your supervisor for further support.");
    } else {

      // 2️⃣ Calculate difference in months (decimal)
      const diffMonths = mcpMoment.diff(lmpMoment, 'months', true);

      // 3️⃣ Apply required category logic
      if (diffMonths >= 0 && diffMonths < 4) {
        value = "In the first 3 months";
      } else if (diffMonths >= 4 && diffMonths < 7) {
        value = "Between 4-6 months";
      } else if (diffMonths >= 7 && diffMonths <= 9) {
        value = "Between 7-9 months";
      } else {
        validationErrors.push("either the MCP card registration or the LMP date is incorrect. Please contact your supervisor for further support.");
      }
    }
  }

  return new imports.rulesConfig.FormElementStatus(
    formElement.uuid,
    visibility,
    value,
    answersToSkip,
    validationErrors
  );
};

